package main

import "fmt"

// Expects a string called 'name'
func greet(name string) {
    fmt.Println("Welcome back,", name)
}

// Expects two integers called 'a' and 'b'
func add(a int, b int) {
    fmt.Println("Sum:", a + b)
}

func main() {
    greet("Alice")
    add(50, 25)
}
